var argv = require('optimist')
	.describe('input', 'Listen for inputs or not.')
	.default('input', 1)
	.alias('i', 'input')
	.describe('output', 'Output array')
	//.default('oupput', 0)
	.alias('o', 'output')
	.argv;

var vita = require('..')
	,async = require('async');

var an2054;

if (argv.output) an2054 = vita.open("usb:CLASS_AN2054/00107821");
else an2054 = vita.open("usb:CLASS_AN2054/00000000");

var write = function(arr, callback) {
	var buf = new Buffer(arr);
	an2054.setPropertyBuf(1, 0, 0x3D, buf, function(err) {
		if (err) return callback(err);
		console.log('done writing');
		return callback(null);
	});
}

var read = function(length, callback) {
	console.log('reading');
	an2054.getPropertyBuf(1, 0, 0x14, length, function(err, data)  {
		if (err) return callback(err);
		console.log('read data');
		return callback(null, data);
	});
}

var writeByte = function(byte, callback) {
	an2054.setProperty(1, 0, 0x14, byte, function(err) {
		if (err) return callback(err);
		console.log("write byte");
		return callback(null);
	});
}


if (argv.output) {
	argv.input = 0;
	if (!Array.isArray(argv.output)) argv.output = [argv.output];

	write(argv.output, function(err) {
		if (err) throw err;

		an2054.close();
	});
}

if (argv.input) {
	read(argv.input, function(err, data) {
		if (err) throw err;

		console.log(data);
		an2054.close();
	});
}
